fn token_burn<'a>(
    pool_account_key: &Pubkey, token_program: AccountInfo<'a>,
    burn_account: AccountInfo<'a>, mint: AccountInfo<'a>,
    authority: AccountInfo<'a>, bump_seed: u8, amount: u64,
) -> Result<(), ProgramError> {
    let authority_seeds = &[POOL_MINT_AUTHORITY_PREFIX, pool_account_key.as_ref(), &[bump_seed]];
    let signers = &[&authority_seeds[..]];
    let ix = spl_token::instruction::burn(
        token_program.key, burn_account.key, mint.key, authority.key, &[], amount).unwrap();
    let _ = invoke_signed(&ix, &[burn_account, mint, authority], signers);
    Ok(())
}

