pub fn process_burn(
    program_id: &Pubkey,
    accounts: &[AccountInfo],
    amount: u64,
    expected_decimals: Option<u8>,
) -> ProgramResult {
    let account_info_iter = &mut accounts.iter();
    let source_account_info = next_account_info(account_info_iter)?;
    let mint_info = next_account_info(account_info_iter)?;
    let authority_info = next_account_info(account_info_iter)?;

    let mut source_account = Account::unpack(&source_account_info.data.borrow())?;
    let mut mint = Mint::unpack(&mint_info.data.borrow())?;

    if source_account.is_frozen() {
        return Err(TokenError::AccountFrozen.into());
    }
    if source_account.amount < amount {
        return Err(TokenError::InsufficientFunds.into());
    }
    if !Self::cmp_pubkeys(mint_info.key, &source_account.mint) {
        return Err(TokenError::MintMismatch.into());
    }

    match source_account.delegate {
        COption::Some(ref delegate) if Self::cmp_pubkeys(authority_info.key, delegate) => {
            Self::validate_owner(program_id, delegate, authority_info, account_info_iter.as_slice())?;
            if source_account.delegated_amount < amount {
                return Err(TokenError::InsufficientFunds.into());
            }
            source_account.delegated_amount = source_account.delegated_amount
                .checked_sub(amount).ok_or(TokenError::Overflow)?;
        }
        _ => Self::validate_owner(program_id, &source_account.owner, authority_info, account_info_iter.as_slice())?,
    }

    source_account.amount = source_account.amount
        .checked_sub(amount).ok_or(TokenError::Overflow)?;
    mint.supply = mint.supply
        .checked_sub(amount).ok_or(TokenError::Overflow)?;

    Account::pack(source_account, &mut source_account_info.data.borrow_mut())?;
    Mint::pack(mint, &mut mint_info.data.borrow_mut())?;
    Ok(())
}

