    let CalculateLiquidationResult { settle_amount, repay_amount, withdraw_amount }
        = withdraw_reserve.calculate_liquidation(liquidity_amount, &obligation, liquidity, collateral)?;

    if repay_amount == 0 {
        return Err(LendingError::LiquidationTooSmall.into());
