fn process_flash_loan(
    program_id: &Pubkey,
    liquidity_amount: u64,
    accounts: &[AccountInfo],
) -> ProgramResult {
    let mut reserve = Reserve::unpack(&reserve_info.data.borrow())?;

    if program_id == flash_loan_receiver_program_id.key {
        return Err(LendingError::InvalidFlashLoanReceiverProgram.into());
    }

    let balance_before = Account::unpack(&source_liquidity_info.data.borrow())?.amount;
    let expected_balance_after = balance_before
        .checked_add(origination_fee)
        .ok_or(LendingError::MathOverflow)?;

    reserve.liquidity.borrow(flash_loan_amount_decimal)?;
    Reserve::pack(reserve, &mut reserve_info.data.borrow_mut())?;

    // Transfer funds OUT to borrower
    spl_token_transfer(TokenTransferParams {
        source: source_liquidity_info.clone(),
        destination: destination_liquidity_info.clone(),
        amount: flash_loan_amount,
        authority: lending_market_authority_info.clone(),
        authority_signer_seeds,
        token_program: token_program_id.clone(),
    })?;

    // Invoke external flash loan receiver (untrusted CPI)
    invoke(
        &Instruction {
            program_id: *flash_loan_receiver_program_id.key,
            accounts: flash_loan_instruction_accounts,
            data,
        },
        &flash_loan_instruction_account_infos[..],
    )?;

    // Re-read reserve and verify repayment
    reserve = Reserve::unpack(&reserve_info.data.borrow())?;
    reserve.liquidity.repay(flash_loan_amount, flash_loan_amount_decimal)?;
    Reserve::pack(reserve, &mut reserve_info.data.borrow_mut())?;

    let actual_balance = Account::unpack(&source_liquidity_info.data.borrow())?.amount;
    if actual_balance < expected_balance_after {
        return Err(LendingError::NotEnoughLiquidityAfterFlashLoan.into());
    }

    Ok(())
}

