) -> ProgramResult {
    let account_info_iter = &mut accounts.iter();
    let pool_info = next_account_info(account_info_iter)?;
    let authority_info = next_account_info(account_info_iter)?;

    let authority = Pubkey::create_program_address(
        &[&pool_info.key.to_bytes()[..32], &[args.bump_seed]],
        program_id,
    ).map_err(|_| PoolError::InvalidAuthorityData)?;

    if *authority_info.key != authority {
        return Err(PoolError::InvalidAuthorityAccount.into());
    }

    let mut pool = Pool::try_from_slice(&pool_info.data.borrow())?;
    pool.bump_seed = args.bump_seed;
    pool.mint_end_slot = args.mint_end_slot;
    pool.decide_end_slot = args.decide_end_slot;

    borsh::to_writer(&mut pool_info.data.borrow_mut()[..], &pool)?;
    Ok(())
}

